 286→router.get('/getNotifications', requireAuth, async(req, res) =>{
 287→    const {before, limit} = req.query;
 288→    const userId = req.userId;
 289→
 290→    // Fetch a generous amount from both tables, then merge and paginate
 291→    const fetchLimit = parseInt(limit) + 1;
 292→
 293→    let journalQuery = supabase
 294→    .from('notifications')
 295→    .select(
 296→        `*,
 297→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 298→        users!sender_id(name, user_email, image_url, id, badge)
 299→        `
 300→    )
 301→    .eq('receiver_id', userId)
 302→    .order('created_at', {ascending: false})
 303→    .order('id', {ascending: false})
 304→    .limit(fetchLimit)
 305→
 306→    let opinionQuery = supabase
 307→    .from('notification_opinions')
 308→    .select(
 309→        `*,
 310→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 311→        users!sender_id(name, user_email, image_url, id, badge)
 312→        `
 313→    )
 314→    .eq('receiver_id', userId)
 315→    .order('created_at', {ascending: false})
 316→    .order('id', {ascending: false})
 317→    .limit(fetchLimit)
 318→
 319→    if(before){
 320→        journalQuery = journalQuery.lt('created_at', before);
 321→        opinionQuery = opinionQuery.lt('created_at', before);
 322→    }
 323→
 324→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 325→
 326→    if(journalResult.error){
 327→        console.error('error while fetching data from notification table:', journalResult.error);
 328→        return res.status(500).json({error: 'error fetching data from notification table'});
 329→    }
 330→    if(opinionResult.error){
 331→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 332→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 333→    }
 334→
 335→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 336→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 337→
 338→    // Merge and sort by created_at descending
 339→    const merged = [...journalNotifs, ...opinionNotifs]
 340→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 341→
 342→    // Likes/bookmarks lookup only for journal notifications
 343→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 344→
 345→    let hasLikedResult = [];
 346→    let hasBookMarkedResult = [];
 347→    if(journalIds.length > 0){
 348→        const [hasLiked, hasBookMarked] = await Promise.all([
 349→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 350→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 351→        ]);
 352→
 353→        if(hasLiked.error || hasBookMarked.error){
 354→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 355→        }
 356→        hasLikedResult = hasLiked.data || [];
 357→        hasBookMarkedResult = hasBookMarked.data || [];
 358→    }
 359→
 360→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 361→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 362→
 363→    const formatted = merged.map((notif) => ({
 364→        ...notif,
 365→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 366→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 367→    }))
 368→
 369→    const hasMore = formatted.length > parseInt(limit);
 370→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 371→
 372→    return res.status(200).json(
 373→        {
 374→            hasMore: hasMore,
 375→            data: slicedData,
 376→        }
 377→    )
 378→
 379→})
