241→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
242→    let payload = {
243→        user_id: userId,
244→        title: trimmedTitle,
245→        post_type: resolvedPostType
246→    };
247→
248→    if(resolvedPostType === POST_TYPE_CANVAS){
249→        let parsedCanvasDoc = null;
