 185→const resolveMediaUrl = async(bucket, path) => {
 186→    const {data: signedUrlData, error: signedUrlError} = await supabase.storage
 187→        .from(bucket)
 188→        .createSignedUrl(path, 60 * 60);
 189→
 190→    if(!signedUrlError && signedUrlData?.signedUrl){
 191→        return signedUrlData.signedUrl;
 192→    }
 193→
 194→    const {data: publicUrlData} = supabase.storage
 195→        .from(bucket)
 196→        .getPublicUrl(path);
