 201→const listMediaChunkForBucket = async(bucket, userId, offset, limit) => {
 202→    const folderPath = `user_id_${userId}`;
 203→
 204→    const {data: bucketItems, error: bucketError} = await supabase.storage
 205→        .from(bucket)
 206→        .list(folderPath, {
 207→            limit: limit,
 208→            offset: offset,
 209→            sortBy: {column: 'name', order: 'desc'}
 210→        });
 211→
 212→    if(bucketError){
 213→        return {
 214→            bucket: bucket,
 215→            nextOffset: offset,
 216→            exhausted: true,
 217→            items: [],
 218→            error: bucketError.message
 219→        };
 220→    }
 221→
 222→    const listedItems = Array.isArray(bucketItems) ? bucketItems : [];
 223→    const normalizedItems = listedItems
 224→        .filter((item) => item?.name && hasSupportedMediaExtension(item.name))
 225→        .map((item) => {
 226→            const path = `${folderPath}/${item.name}`;
 227→            const createdAt = item.created_at || item.updated_at || null;
 228→
 229→            return {
 230→                bucket: bucket,
 231→                path: path,
 232→                name: item.name,
 233→                createdAt: createdAt,
 234→                timestamp: parseMediaTimestamp(item)
 235→            };
 236→        });
 237→
 238→    return {
 239→        bucket: bucket,
 240→        nextOffset: offset + listedItems.length,
 241→        exhausted: listedItems.length < limit,
 242→        items: normalizedItems,
 243→        error: null
 244→    };
 245→};
