 247→const hydrateMediaItems = async(items) => {
 248→    if(!Array.isArray(items) || items.length === 0){
 249→        return [];
 250→    }
 251→
 252→    const hydrated = await Promise.all(items.map(async(item) => {
 253→        const url = await resolveMediaUrl(item.bucket, item.path);
 254→        if(!url){
 255→            return null;
 256→        }
 257→
 258→        return {
 259→            id: `${item.bucket}-${item.path}`,
 260→            bucket: item.bucket,
 261→            path: item.path,
 262→            name: item.name,
 263→            createdAt: item.createdAt || null,
 264→            timestamp: item.timestamp || 0,
 265→            url: url
 266→        };
 267→    }));
 268→
 269→    return hydrated.filter(Boolean);
 270→};
