 272→export const getProfileMediaService = async(userId, limit = PROFILE_MEDIA_LIMIT_DEFAULT, cursor = null) => {
 273→    if(!userId){
 274→        throw {status: 400, error: 'userId is undefined'};
 275→    }
 276→
 277→    const parsedLimit = Number(limit);
 278→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > PROFILE_MEDIA_LIMIT_MAX){
 279→        throw {status: 400, error: `limit should be an integer between 1 and ${PROFILE_MEDIA_LIMIT_MAX}`};
 280→    }
 281→
 282→    const cursorState = parseMediaCursor(cursor);
 283→    const offsets = {...cursorState.offsets};
 284→    const exhausted = {...cursorState.exhausted};
 285→    const pending = Array.isArray(cursorState.pending) ? [...cursorState.pending] : [];
 286→    const unavailableBuckets = [];
 287→    const maxIterations = 6;
 288→    let iterationCount = 0;
 289→
 290→    while(
 291→        pending.length < parsedLimit &&
 292→        PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]) &&
 293→        iterationCount < maxIterations
 294→    ){
 295→        iterationCount += 1;
 296→        const activeBuckets = PROFILE_MEDIA_BUCKETS.filter((bucket) => !exhausted[bucket]);
 297→        const chunkResults = await Promise.all(
 298→            activeBuckets.map((bucket) => listMediaChunkForBucket(bucket, userId, offsets[bucket] || 0, parsedLimit))
 299→        );
 300→
 301→        chunkResults.forEach((result) => {
 302→            offsets[result.bucket] = result.nextOffset;
 303→            exhausted[result.bucket] = result.exhausted;
 304→
 305→            if(result.error){
 306→                console.error(`supabase storage list error on ${result.bucket}:`, result.error);
 307→                unavailableBuckets.push(result.bucket);
 308→                return;
 309→            }
 310→
 311→            pending.push(...result.items);
 312→        });
 313→
 314→        if(chunkResults.every((result) => result.items.length === 0)){
 315→            break;
 316→        }
 317→    }
 318→
 319→    pending.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
 320→
 321→    const selectedItems = pending.slice(0, parsedLimit);
 322→    const remainingItems = pending.slice(parsedLimit);
 323→    const hydratedSelectedItems = await hydrateMediaItems(selectedItems);
 324→
 325→    // If a URL cannot be created for some selected items, try to fill from remaining items.
 326→    if(hydratedSelectedItems.length < parsedLimit && remainingItems.length > 0){
 327→        const neededItemsCount = parsedLimit - hydratedSelectedItems.length;
 328→        const fallbackCandidates = remainingItems.splice(0, neededItemsCount);
 329→        const hydratedFallbackItems = await hydrateMediaItems(fallbackCandidates);
 330→        hydratedSelectedItems.push(...hydratedFallbackItems);
 331→    }
 332→
 333→    const hasMore = remainingItems.length > 0 || PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]);
 334→    const dedupedUnavailableBuckets = [...new Set(unavailableBuckets)];
 335→
 336→    const nextCursor = hasMore
 337→        ? encodeMediaCursor({
 338→            offsets: offsets,
 339→            exhausted: exhausted,
 340→            pending: remainingItems
 341→        })
 342→        : null;
 343→
 344→    return {
 345→        data: hydratedSelectedItems,
 346→        hasMore: hasMore,
 347→        nextCursor: nextCursor,
 348→        unavailableBuckets: dedupedUnavailableBuckets
 349→    };
 350→}
