 442→export const getMonthlyHottestJournalsService = async(limit, userId) => {
 443→    if(isNaN(limit) || limit < 1 || limit > 10){
 444→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
 445→    }
 446→
 447→    const parsedLimit = parseInt(limit);
 448→    const now = new Date();
 449→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
 450→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
 451→
 452→    const {data: journals, error: journalsError} = await supabase
 453→        .from('journals')
 454→        .select(`
 455→            *,
 456→            users(*),
 457→            like_count: likes(count),
 458→            comment_count: comments(count),
 459→            bookmark_count: bookmarks(count)
 460→        `)
 461→        .eq('privacy', 'public')
 462→        .gte('created_at', monthStartUtc.toISOString())
 463→        .lt('created_at', nextMonthStartUtc.toISOString());
 464→
 465→    if(journalsError){
 466→        console.error('supabase error while fetching monthly hottest journals:', journalsError.message);
 467→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
 468→    }
 469→
 470→    const journalsWithInteractions = await attachUserInteractionFlags(journals || [], userId);
 471→    const scored = journalsWithInteractions.map((journal) => {
 472→        const likes = journal?.like_count?.[0]?.count || 0;
 473→        const comments = journal?.comment_count?.[0]?.count || 0;
 474→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 475→        const views = journal?.views || 0;
 476→        const hotScore = (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 477→
 478→        return {
 479→            ...journal,
 480→            hot_score: hotScore
 481→        };
 482→    });
 483→
 484→    scored.sort((a, b) => {
 485→        const scoreDiff = (b?.hot_score || 0) - (a?.hot_score || 0);
 486→        if(scoreDiff !== 0){
 487→            return scoreDiff;
 488→        }
 489→
 490→        const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 491→        if(dateDiff !== 0){
 492→            return dateDiff;
 493→        }
 494→
 495→        return (b?.id || 0) - (a?.id || 0);
 496→    });
 497→
 498→    return {
 499→        data: scored.slice(0, parsedLimit),
 500→        period: {
 501→            startUtc: monthStartUtc.toISOString(),
 502→            endUtc: nextMonthStartUtc.toISOString(),
 503→            timezone: 'UTC'
 504→        },
 505→        totalCandidates: scored.length
 506→    };
 507→}
