 511→    const comments = journal?.comment_count?.[0]?.count || 0;
 512→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 513→    const views = journal?.views || 0;
 514→    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
