 517→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
 518→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
 519→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
 520→    }
 521→
 522→    const parsedLimit = parseInt(limit);
 523→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
 524→    const isNewest = normalizedSort === 'newest';
 525→    const parsedCursor = parseCanvasGalleryCursor(cursor, isNewest ? 'newest' : 'hottest');
 526→    const cursorOffset = parsedCursor.offset;
 527→
 528→    const baseQuery = supabase
 529→        .from('journals')
 530→        .select(`
 531→            *,
 532→            users(*),
 533→            like_count: likes(count),
 534→            comment_count: comments(count),
 535→            bookmark_count: bookmarks(count),
 536→            stamp_count: canvas_stamps(count),
 537→            margin_count: canvas_margin_items(count)
 538→        `)
 539→        .eq('privacy', 'public')
 540→        .eq('post_type', 'canvas')
 541→        .order('created_at', {ascending: false})
 542→        .order('id', {ascending: false});
 543→
 544→    const {data: journals, error: journalsError} = isNewest
 545→        ? await baseQuery.range(cursorOffset, cursorOffset + parsedLimit)
 546→        : await baseQuery.limit(CANVAS_GALLERY_HOT_FETCH_LIMIT);
 547→
 548→    if(journalsError){
 549→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
 550→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
 551→    }
 552→
 553→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
 554→    const normalizedJournals = enrichedJournals.map((journal) => ({
 555→        ...journal,
 556→        hot_score: scoreJournalHotness(journal)
 557→    }));
 558→
 559→    if(!isNewest){
 560→        normalizedJournals.sort((a, b) => {
 561→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
 562→            if(scoreDiff !== 0){
 563→                return scoreDiff;
 564→            }
 565→
 566→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 567→            if(dateDiff !== 0){
 568→                return dateDiff;
 569→            }
 570→
 571→            return (b?.id || 0) - (a?.id || 0);
 572→        });
 573→    }
 574→
 575→    const paginatedJournals = isNewest
 576→        ? normalizedJournals
 577→        : normalizedJournals.slice(cursorOffset, cursorOffset + parsedLimit + 1);
 578→    const hasMore = paginatedJournals.length > parsedLimit;
 579→    const data = hasMore ? paginatedJournals.slice(0, parsedLimit) : paginatedJournals;
 580→    const nextCursor = hasMore
 581→        ? encodeCanvasGalleryCursor(cursorOffset + data.length, isNewest ? 'newest' : 'hottest')
 582→        : null;
 583→
 584→    return {
 585→        data: data,
 586→        sort: isNewest ? 'newest' : 'hottest',
 587→        totalCandidates: normalizedJournals.length,
 588→        hasMore: hasMore,
 589→        nextCursor: nextCursor
 590→    };
 591→}
