  1→import { mulberry32 } from './proceduralGeneration';
  2→import { simpleHash, hexToRgba } from './starUtils';
  3→
  4→// Parse hex color to {r, g, b}
  5→const hexToRgb = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→// Lerp between two {r,g,b} objects
 12→const lerpColor = (a, b, t) => ({
 13→    r: Math.round(a.r + (b.r - a.r) * t),
 14→    g: Math.round(a.g + (b.g - a.g) * t),
 15→    b: Math.round(a.b + (b.b - a.b) * t),
 16→});
 17→
 18→const WARM = hexToRgb('#ffd7a0');
 19→const COOL = hexToRgb('#4a7fff');
 20→
 21→/**
 22→ * Generate deterministic spiral galaxy data for a user.
 23→ * All positions are relative to (0,0) — caller offsets by galaxy center.
 24→ */
 25→export const generateGalaxyData = (userId) => {
 26→    const seed = simpleHash(userId) + 7919;
 27→    const rng = mulberry32(seed);
 28→
 29→    const armCount = 2 + Math.floor(rng() * 3); // 2-4
 30→    const rotation = rng() * Math.PI * 2;
 31→    const axialTilt = 0.45 + rng() * 0.3; // 0.45-0.75
 32→    const winding = 2.5 + rng() * 1.5; // 2.5-4.0
 33→    const galaxyRadius = 250 + rng() * 100; // 250-350
 34→    const coreSize = 0.18 + rng() * 0.1; // 0.18-0.28
 35→    const coreRadius = galaxyRadius * coreSize;
 36→
 37→    // Pre-compute arm particles
 38→    const particleCount = 300;
 39→    const particles = new Array(particleCount);
 40→
 41→    for (let i = 0; i < particleCount; i++) {
 42→        const armIndex = i % armCount;
 43→        const t = rng() * winding;
 44→        const progress = t / winding; // 0 = core, 1 = outer edge
 45→
 46→        // Archimedean spiral
 47→        const r = coreRadius + (galaxyRadius - coreRadius) * progress;
 48→        const theta = t + (armIndex / armCount) * Math.PI * 2 + rotation;
 49→
 50→        // Scatter perpendicular to arm — wider at outer edges
 51→        const spread = 8 + progress * 35;
 52→        const scatter = (rng() - 0.5) * 2 * spread;
 53→        const tangentAngle = theta + Math.PI / 2;
 54→
 55→        const x = r * Math.cos(theta) + scatter * Math.cos(tangentAngle);
 56→        const y = (r * Math.sin(theta) + scatter * Math.sin(tangentAngle)) * axialTilt;
 57→
 58→        const dotRadius = 0.6 + rng() * 1.8;
 59→        const alpha = 0.15 + rng() * 0.45;
 60→
 61→        particles[i] = { x, y, radius: dotRadius, progress, alpha };
 62→    }
 63→
 64→    // Pre-compute arm curve polylines for glow strokes
 65→    const armCurves = [];
 66→    const curveSteps = 40;
 67→    for (let a = 0; a < armCount; a++) {
 68→        const points = new Array(curveSteps);
 69→        for (let s = 0; s < curveSteps; s++) {
 70→            const t = (s / (curveSteps - 1)) * winding;
 71→            const r = coreRadius + (galaxyRadius - coreRadius) * (t / winding);
 72→            const theta = t + (a / armCount) * Math.PI * 2 + rotation;
 73→            points[s] = {
 74→                x: r * Math.cos(theta),
 75→                y: r * Math.sin(theta) * axialTilt,
 76→            };
 77→        }
 78→        armCurves.push(points);
 79→    }
 80→
 81→    return { galaxyRadius, coreRadius, axialTilt, particles, armCurves };
 82→};
 83→
 84→/**
 85→ * Draw all galaxy visuals + connection lines onto a single canvas context.
 86→ * Each entry in `galaxies` must have: x, y, color, galaxyRadius, coreRadius, particles, armCurves.
 87→ */
 88→export const drawGalaxyVisuals = (ctx, galaxies) => {
 89→    if (!galaxies || galaxies.length === 0) return;
 90→
 91→    // --- Draw each galaxy ---
 92→    for (let g = 0; g < galaxies.length; g++) {
 93→        const gal = galaxies[g];
 94→        const { x: cx, y: cy, color, galaxyRadius, coreRadius, particles, armCurves } = gal;
 95→        const accent = hexToRgb(color);
 96→
 97→        // 1. Outer halo
 98→        const haloGrad = ctx.createRadialGradient(cx, cy, coreRadius, cx, cy, galaxyRadius * 1.2);
 99→        haloGrad.addColorStop(0, hexToRgba(color, 0.08));
100→        haloGrad.addColorStop(0.6, hexToRgba(color, 0.03));
101→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
102→        ctx.fillStyle = haloGrad;
103→        ctx.beginPath();
104→        ctx.arc(cx, cy, galaxyRadius * 1.2, 0, Math.PI * 2);
105→        ctx.fill();
106→
107→        // 2. Arm particles
108→        for (let i = 0; i < particles.length; i++) {
109→            const p = particles[i];
110→            // Color: inner = warm lerp with accent, outer = cool lerp with accent
111→            let c;
112→            if (p.progress < 0.5) {
113→                const t = p.progress / 0.5;
114→                c = lerpColor(WARM, accent, t);
115→            } else {
116→                const t = (p.progress - 0.5) / 0.5;
117→                c = lerpColor(accent, COOL, t);
118→            }
119→            ctx.fillStyle = `rgba(${c.r},${c.g},${c.b},${p.alpha})`;
120→            ctx.beginPath();
121→            ctx.arc(cx + p.x, cy + p.y, p.radius, 0, Math.PI * 2);
122→            ctx.fill();
123→        }
124→
125→        // 3. Arm glow lines
126→        ctx.strokeStyle = hexToRgba(color, 0.08);
127→        ctx.lineWidth = 1.5;
128→        for (let a = 0; a < armCurves.length; a++) {
129→            const pts = armCurves[a];
130→            ctx.beginPath();
131→            ctx.moveTo(cx + pts[0].x, cy + pts[0].y);
132→            for (let s = 1; s < pts.length; s++) {
133→                ctx.lineTo(cx + pts[s].x, cy + pts[s].y);
134→            }
135→            ctx.stroke();
136→        }
137→
138→        // 4. Core glow — multi-stop radial gradient
139→        const coreGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, coreRadius * 2);
140→        coreGrad.addColorStop(0, 'rgba(255,255,255,0.9)');
141→        coreGrad.addColorStop(0.15, 'rgba(255,248,220,0.6)');
142→        coreGrad.addColorStop(0.5, hexToRgba(color, 0.3));
143→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
144→        ctx.fillStyle = coreGrad;
145→        ctx.beginPath();
146→        ctx.arc(cx, cy, coreRadius * 2, 0, Math.PI * 2);
147→        ctx.fill();
148→    }
149→
150→    // --- Connection lines between nearby galaxies ---
151→    const MAX_DIST = 5000;
152→    const MAX_DIST_SQ = MAX_DIST * MAX_DIST;
153→
154→    for (let i = 0; i < galaxies.length; i++) {
155→        for (let j = i + 1; j < galaxies.length; j++) {
156→            const a = galaxies[i];
157→            const b = galaxies[j];
158→            const dx = b.x - a.x;
159→            const dy = b.y - a.y;
160→            const distSq = dx * dx + dy * dy;
161→            if (distSq > MAX_DIST_SQ) continue;
162→
163→            const dist = Math.sqrt(distSq);
164→            // Fade out as distance approaches max
165→            const fade = 1 - dist / MAX_DIST;
166→            const opacity = 0.06 * fade;
167→
168→            // Midpoint with perpendicular offset for a gentle arc
169→            const mx = (a.x + b.x) / 2;
170→            const my = (a.y + b.y) / 2;
171→            const perpX = -dy / dist * dist * 0.1;
172→            const perpY = dx / dist * dist * 0.1;
173→
174→            ctx.strokeStyle = `rgba(255,255,255,${opacity})`;
175→            ctx.lineWidth = 0.5;
176→            ctx.beginPath();
177→            ctx.moveTo(a.x, a.y);
178→            ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
179→            ctx.stroke();
180→        }
181→    }
182→};
