 4→import { generateDeepSpaceStars, generateNebulae } from '../utils/proceduralGeneration';
 5→
 6→const DeepSpaceLayer = React.memo(({ layerProps }) => {
 7→    const dustStars = useMemo(() => generateDeepSpaceStars(2000, 42), []);
 8→    const nebulae = useMemo(() => generateNebulae(18, 256), []);
 9→
10→    return (
11→        <Layer {...layerProps} listening={false}>
12→            {/* Nebulae (behind dust) */}
