15→                    key={i}
16→                    x={n.x}
17→                    y={n.y}
18→                    radius={n.radius}
19→                    opacity={n.opacity}
20→                    color={n.color}
21→                />
22→            ))}
23→            {/* Dust stars — batch-drawn via single Shape for performance */}
24→            <Shape
25→                sceneFunc={(ctx) => {
26→                    ctx.fillStyle = '#ffffff';
