28→                        const s = dustStars[i];
29→                        ctx.globalAlpha = s.opacity;
30→                        ctx.beginPath();
31→                        ctx.arc(s.x, s.y, s.radius, 0, Math.PI * 2);
32→                        ctx.fill();
33→                    }
34→                    ctx.globalAlpha = 1;
35→                }}
36→                perfectDrawEnabled={false}
37→                listening={false}
38→            />
39→        </Layer>
40→    );
