22→            fillRadialGradientStartRadius={0}
23→            fillRadialGradientEndRadius={radius * layer.rFactor}
24→            fillRadialGradientColorStops={[
25→                0, hexToRgba(color, opacity * layer.opFactor),
26→                1, hexToRgba(color, 0),
